static func chain<A, B, C, D>() -> EpoxyModelProperty<((A, B, C, D) -> Void)?>.UpdateStrategy {
  .init { old, new in
    guard let new else { return old }
    guard let old else { return new }
    return { a, b, c, d in
      old(a, b, c, d)
      new(a, b, c, d)
    }
  }
}

