func remap(fromLow: CGFloat, fromHigh: CGFloat, toLow: CGFloat, toHigh: CGFloat) -> CGFloat {
  guard (fromHigh - fromLow) != 0 else {
    // Would produce NAN
    return 0
  }
  return toLow + (self - fromLow) * (toHigh - toLow) / (fromHigh - fromLow)
}

func encode(_ key: String) -> String {
    switch self {
    case .useDefaultKeys: key
    case .convertToSnakeCase: convertToSnakeCase(key)
    case .convertToKebabCase: convertToKebabCase(key)
    case .capitalized: String(key.prefix(1).uppercased() + key.dropFirst())
    case .uppercased: key.uppercased()
    case .lowercased: key.lowercased()
    case let .custom(encoding): encoding(key)
    }
}

func addingPrefixWithAutodetectedStyle(_ prefix: String) -> String {
  if contains("-") {
    return "\(prefix)-\(self)"
  } else if contains("_") {
    return "\(prefix)_\(self)"
  } else if first?.isLowercase == true && contains(where: { $0.isUppercase })
  {
    return addingIntercappedPrefix(prefix)
  } else {
    return "\(prefix)-\(self)"
  }
}

@inlinable
  public func index(before i: Index) -> Index {
    assert(i != startIndex, "Can't advance before startIndex")
    switch i.position {
    case .first(let i):
      return Index(first: base1.index(before: i))
    case .second(let i):
      return i == base2.startIndex
        ? Index(first: base1.index(before: base1.endIndex))
        : Index(second: base2.index(before: i))
    }
  }

@inlinable
  internal func index(
    _ i: Index,
    offsetBy distance: Int,
    limitedBy limit: Index
  ) -> Index? {
    switch (self, i, limit) {
    case (.left(let s), .left(let i), .left(let limit)):
      return s.index(i, offsetBy: distance, limitedBy: limit).map { .left($0) }
    case (.right(let s), .right(let i), .right(let limit)):
      return s.index(i, offsetBy: distance, limitedBy: limit).map { .right($0) }
    default:
      fatalError()
    }
  }

public init(_ intValue: Int) {
  let isNegative = intValue < 0
  let intValue = isNegative ? -intValue : intValue
  var hexString = String(format: "%016llx", intValue)
  hexString.insert("-", at: hexString.index(hexString.startIndex, offsetBy: 4))
  self.init(uuidString: "00000000-0000-000\(isNegative ? "1" : "0")-\(hexString)")!
}

