@inlinable
  internal init<R: RangeExpression>(
    _ base: Base,
    kRange: R?
  ) where R.Bound == Int {
    self.base = base
    let baseCount = base.count
    self.baseCount = baseCount
    let upperBound = baseCount + 1
    self.kRange =
      kRange?.relative(to: 0 ..< .max)
      .clamped(to: 0..<upperBound) ?? baseCount..<upperBound
  }

@inlinable
  public func index(before i: Index) -> Index {
    precondition(
      i != startIndex,
      "Can't move before startIndex")
    guard i.i2 == base2.startIndex else {
      return Index(i1: i.i1, i2: base2.index(before: i.i2))
    }
    return Index(
      i1: base1.index(before: i.i1),
      i2: base2.index(before: base2.endIndex))
  }

